147: /// Manages a sequence of passes over a particular unit of IR.
148: ///
149: /// A pass manager contains a sequence of passes to run over a particular unit
150: /// of IR (e.g. Functions, Modules). It is itself a valid pass over that unit of
151: /// IR, and when run over some given IR will run each of its contained passes in
152: /// sequence. Pass managers are the primary and most basic building block of a
153: /// pass pipeline.
154: ///
155: /// When you run a pass manager, you provide an \c AnalysisManager<IRUnitT>
156: /// argument. The pass manager will propagate that analysis manager to each
157: /// pass it runs, and will call the analysis manager's invalidation routine with
158: /// the PreservedAnalyses of each pass it runs.
159: template <typename IRUnitT,
160:           typename AnalysisManagerT = AnalysisManager<IRUnitT>,
161:           typename... ExtraArgTs>
162: class PassManager : public PassInfoMixin<
163:                         PassManager<IRUnitT, AnalysisManagerT, ExtraArgTs...>> {
164: public:
165:   /// Construct a pass manager.
166:   explicit PassManager() = default;
167: 
168:   // FIXME: These are equivalent to the default move constructor/move
169:   // assignment. However, using = default triggers linker errors due to the
170:   // explicit instantiations below. Find away to use the default and remove the
171:   // duplicated code here.
172:   PassManager(PassManager &&Arg) : Passes(std::move(Arg.Passes)) {}
173: 
174:   PassManager &operator=(PassManager &&RHS) {
175:     Passes = std::move(RHS.Passes);
176:     return *this;
177:   }
178: 
179:   void printPipeline(raw_ostream &OS,
180:                      function_ref<StringRef(StringRef)> MapClassName2PassName) {
181:     ListSeparator LS(",");
182:     for (auto &P : Passes) {
183:       OS << LS;
184:       P->printPipeline(OS, MapClassName2PassName);
185:     }
186:   }
187: 
188:   /// Run all of the passes in this manager over the given unit of IR.
189:   /// ExtraArgs are passed to each pass.
190:   PreservedAnalyses run(IRUnitT &IR, AnalysisManagerT &AM,
191:                         ExtraArgTs... ExtraArgs);
192: 
193:   template <typename PassT>
194:   LLVM_ATTRIBUTE_MINSIZE std::enable_if_t<!std::is_same_v<PassT, PassManager>>
195:   addPass(PassT &&Pass) {
196:     using PassModelT =
197:         detail::PassModel<IRUnitT, PassT, AnalysisManagerT, ExtraArgTs...>;
198:     // Do not use make_unique or emplace_back, they cause too many template
199:     // instantiations, causing terrible compile times.
200:     Passes.push_back(std::unique_ptr<PassConceptT>(
201:         new PassModelT(std::forward<PassT>(Pass))));
202:   }
203: 
204:   /// When adding a pass manager pass that has the same type as this pass
205:   /// manager, simply move the passes over. This is because we don't have
206:   /// use cases rely on executing nested pass managers. Doing this could
207:   /// reduce implementation complexity and avoid potential invalidation
208:   /// issues that may happen with nested pass managers of the same type.
209:   template <typename PassT>
210:   LLVM_ATTRIBUTE_MINSIZE std::enable_if_t<std::is_same_v<PassT, PassManager>>
211:   addPass(PassT &&Pass) {
212:     for (auto &P : Pass.Passes)
213:       Passes.push_back(std::move(P));
214:   }
215: 
216:   /// Returns if the pass manager contains any passes.
217:   bool isEmpty() const { return Passes.empty(); }
218: 
219:   static bool isRequired() { return true; }
220: 
221: protected:
222:   using PassConceptT =
223:       detail::PassConcept<IRUnitT, AnalysisManagerT, ExtraArgTs...>;
224: 
225:   std::vector<std::unique_ptr<PassConceptT>> Passes;
226: };
